}

export default function DoctorFormModal({ doctor, onClose, onSave }: DoctorFormModalProps) {
  const [formData, setFormData] = useState<Omit<Doctor, 'id'>>({
    name: '',
    crm: '',
    cpf: '',
    specialty: '',
    type: 'executante',
    phone: '',
    email: '',
  });

  useEffect(() => {
    if (doctor) {
      setFormData({
        name: doctor.name,
        crm: doctor.crm,
        cpf: doctor.cpf,
        specialty: doctor.specialty,
        type: doctor.type,
        phone: doctor.phone,
        email: doctor.email,
      });
    }
  }, [doctor]);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    onSave({
      id: doctor?.id || Math.random().toString(36).substr(2, 9),
      ...formData,
    });
  };

  const formatCPF = (value: string) => {
    const numbers = value.replace(/\D/g, '');
    return numbers
      .replace(/(\d{3})(\d)/, '$1.$2')
      .replace(/(\d{3})(\d)/, '$1.$2')
      .replace(/(\d{3})(\d{1,2})/, '$1-$2')
      .replace(/(-\d{2})\d+?$/, '$1');
  };

  const formatPhone = (value: string) => {
    const numbers = value.replace(/\D/g, '');
    if (numbers.length <= 10) {
      return numbers
        .replace(/(\d{2})(\d)/, '($1) $2')
        .replace(/(\d{4})(\d)/, '$1-$2')
        .replace(/(-\d{4})\d+?$/, '$1');
    }
    return numbers
      .replace(/(\d{2})(\d)/, '($1) $2')
      .replace(/(\d{5})(\d)/, '$1-$2')
      .replace(/(-\d{4})\d+?$/, '$1');
  };

  return (
    <div className="fixed inset-0 z-[60] flex items-center justify-center bg-slate-900/60 dark:bg-slate-950/80 backdrop-blur-md p-4 animate-in fade-in duration-300">
