'use client';

import React, { useState, useEffect, useCallback } from 'react';
import { motion, AnimatePresence } from 'motion/react';
import { ChevronRight, ChevronLeft, X, Play, Info, Sparkles } from 'lucide-react';
import { cn } from '@/lib/utils';
import { View } from '@/lib/types';

interface Step {
  target: string;
  title: string;
  content: string;
  position: 'top' | 'bottom' | 'left' | 'right' | 'center';
  view?: View;
}

const tourSteps: Step[] = [
  {
    target: 'nav-agenda',
    title: 'Agenda de Atendimentos',
    content: 'O cora├º├úo do sistema. Aqui voc├¬ gerencia seus hor├írios, visualiza agendamentos e realiza encaixes.',
    position: 'right',
    view: 'agenda'
  },
  {
    target: 'header-search',
    title: 'Busca Inteligente',
    content: 'Economize tempo pesquisando pacientes, CPFs ou procedimentos diretamente na barra superior.',
    position: 'bottom'
  },
  {
    target: 'nav-pacientes',
    title: 'Gest├úo de Pacientes',
    content: 'Acesse o cadastro completo, hist├│rico cl├¡nico e dados de contato de todos os seus pacientes.',
    position: 'right',
    view: 'pacientes'
  },
  {
    target: 'nav-medicos',
    title: 'Corpo Cl├¡nico',
    content: 'Gerencie os profissionais da cl├¡nica, suas especialidades e configura├º├Áes de agenda.',
    position: 'right',
    view: 'medicos'
  },
  {
    target: 'nav-historico',
    title: 'Hist├│rico Completo',
    content: 'Consulte cronologicamente todos os atendimentos realizados e o status de cada um.',
    position: 'right',
    view: 'historico'
  },
  {
    target: 'nav-relatorios',
    title: 'Relat├│rios & Dashboards',
    content: 'Analise o desempenho da sua cl├¡nica com m├®tricas detalhadas e gr├íficos intuitivos.',
    position: 'right',
    view: 'relatorios'
  },
  {
    target: 'nav-configuracoes',
    title: 'Configura├º├Áes Avan├ºadas',
    content: 'Customize o sistema: gerencie conv├¬nios, procedimentos, perfis de acesso e muito mais.',
    position: 'right',
    view: 'configuracoes'
  },
  {
    target: 'user-profile-button',
    title: 'Seu Perfil',
    content: 'Personalize suas informa├º├Áes, altere sua senha e gerencie suas prefer├¬ncias de uso.',
    position: 'right'
  }
];

interface GuidedTourProps {
  isOpen: boolean;
  onClose: () => void;
  onSetView: (view: View) => void;
}

export default function GuidedTour({ isOpen, onClose, onSetView }: GuidedTourProps) {
  const [currentStep, setCurrentStep] = useState(0);
  const [targetRect, setTargetRect] = useState<DOMRect | null>(null);

  const step = tourSteps[currentStep];

  const updateTargetRect = useCallback(() => {
    if (!isOpen) return;
    const element = document.getElementById(step.target);
    if (element) {
      setTargetRect(element.getBoundingClientRect());
      element.scrollIntoView({ behavior: 'smooth', block: 'center' });
    } else {
      setTargetRect(null);
    }
  }, [isOpen, step]);

  useEffect(() => {
    if (!isOpen) {
      setCurrentStep(0);
      return;
    }

    // Auto-switch view if required by step
    if (step.view) {
      onSetView(step.view);
    }

    // Small delay to allow new view to render before calculating rect
    const timeoutInitial = setTimeout(updateTargetRect, step.view ? 100 : 0);
    
    // Polling for 1s after step change to catch scroll/layout transitions
    const interval = setInterval(updateTargetRect, 50);
    const timeout = setTimeout(() => clearInterval(interval), 1000);

    const handleEvents = () => updateTargetRect();
    window.addEventListener('resize', handleEvents);
    window.addEventListener('scroll', handleEvents, true);
    
    return () => {
      clearInterval(interval);
      clearTimeout(timeout);
      clearTimeout(timeoutInitial);
      window.removeEventListener('resize', handleEvents);
      window.removeEventListener('scroll', handleEvents, true);
    };
  }, [isOpen, updateTargetRect, currentStep, step.view, onSetView]);

  if (!isOpen) return null;

  const handleNext = () => {
    if (currentStep < tourSteps.length - 1) {
      setCurrentStep(currentStep + 1);
    } else {
      onClose();
    }
  };

  const handleBack = () => {
    if (currentStep > 0) {
      setCurrentStep(currentStep - 1);
    }
  };

  const getCardPosition = () => {
    if (!targetRect || step.position === 'center') {
      return { top: '50%', left: '50%', transform: 'translate(-50%, -50%)' };
    }

    const gap = 24;
    switch (step.position) {
      case 'right':
        return { 
          top: Math.max(20, Math.min(window.innerHeight - 300, targetRect.top)), 
          left: Math.min(window.innerWidth - 420, targetRect.right + gap) 
        };
      case 'bottom':
        return { 
          top: Math.min(window.innerHeight - 300, targetRect.bottom + gap), 
          left: Math.max(20, Math.min(window.innerWidth - 420, targetRect.left + (targetRect.width / 2) - 200)) 
        };
      default:
        return { top: '50%', left: '50%', transform: 'translate(-50%, -50%)' };
    }
  };

  return (
    <div className="fixed inset-0 z-[200] pointer-events-none overflow-hidden">
      {/* Dim Overlay (using shadow from highlight component) */}
      <div className="absolute inset-0 pointer-events-auto overflow-hidden">
        {targetRect && (
          <motion.div
            layoutId="tour-highlight"
            className="absolute bg-transparent shadow-[0_0_0_9999px_rgba(15,23,42,0.7)] rounded-2xl z-10"
            initial={false}
            animate={{
              top: targetRect.top - 8,
              left: targetRect.left - 8,
              width: targetRect.width + 16,
              height: targetRect.height + 16,
            }}
            transition={{ type: 'spring', bounce: 0, duration: 0.4 }}
          >
            {/* Visual pulse border */}
            <div className="absolute inset-0 rounded-2xl ring-4 ring-indigo-500/50 animate-pulse" />
            <div className="absolute inset-0 rounded-2xl border-2 border-indigo-400" />
          </motion.div>
        )}
      </div>

      {/* Tour Card */}
      <AnimatePresence mode="wait">
        <motion.div
          key={currentStep}
          initial={{ opacity: 0, y: 20, scale: 0.95 }}
          animate={{ opacity: 1, y: 0, scale: 1 }}
          exit={{ opacity: 0, y: 10, scale: 0.95 }}
          className="absolute pointer-events-auto w-[calc(100vw-32px)] sm:w-[400px] bg-white rounded-[2.5rem] shadow-2xl border border-white overflow-hidden p-8 flex flex-col z-[210] transition-all duration-500 shadow-indigo-500/10"
          style={getCardPosition()}
        >
          <div className="flex justify-between items-start mb-6">
            <div className="flex items-center gap-3">
              <div className="w-10 h-10 rounded-xl bg-indigo-600 text-white flex items-center justify-center shadow-lg shadow-indigo-100">
                <Sparkles size={20} />
              </div>
              <div>
                <span className="text-[10px] font-bold text-indigo-500 uppercase tracking-widest leading-none">Tour ATAgenda</span>
                <h3 className="text-lg font-bold text-slate-900 leading-tight mt-0.5">{step.title}</h3>
              </div>
            </div>
            <button 
              onClick={onClose}
              className="p-2 text-slate-400 hover:text-slate-600 hover:bg-slate-50 transition-all rounded-full"
            >
              <X size={18} />
            </button>
          </div>

          <p className="text-sm text-slate-600 leading-relaxed mb-8">
            {step.content}
          </p>

          <div className="flex items-center justify-between mt-auto">
            <div className="flex gap-1.5">
              {tourSteps.map((_, i) => (
                <div 
                  key={i} 
                  className={cn(
                    "h-1.5 rounded-full transition-all duration-300",
                    i === currentStep ? "w-6 bg-indigo-600" : "w-1.5 bg-slate-200"
                  )}
                />
              ))}
            </div>

            <div className="flex gap-2">
              {currentStep > 0 && (
                <button 
                  onClick={handleBack}
                  className="p-2 text-slate-400 hover:text-indigo-600 transition-colors"
                >
                  <ChevronLeft size={24} />
                </button>
              )}
              <button 
                onClick={handleNext}
                className="flex items-center gap-2 px-6 py-2.5 bg-indigo-600 text-white rounded-xl text-sm font-bold hover:bg-indigo-700 transition-all shadow-lg shadow-indigo-100 active:scale-95"
              >
                {currentStep === tourSteps.length - 1 ? 'Finalizar' : 'Pr├│ximo'}
                {currentStep < tourSteps.length - 1 && <ChevronRight size={18} />}
              </button>
            </div>
          </div>
        </motion.div>
      </AnimatePresence>
    </div>
  );
}

'use client';

import React, { useState, useEffect } from 'react';
import { X, Save, User, CreditCard, Calendar, Phone, Mail, ChevronDown, Hash } from 'lucide-react';
import { Patient } from '@/lib/types';
import { mockPatients } from '@/lib/mockData';
import CustomSelect from './CustomSelect';

interface PatientFormModalProps {
  patient?: Patient | null;
  onClose: () => void;
  onSave: (patient: Patient) => void;
}

export default function PatientFormModal({ patient, onClose, onSave }: PatientFormModalProps) {
  const [formData, setFormData] = useState<Omit<Patient, 'id'>>({
    name: '',
    cpf: '',
    birthDate: '',
    gender: 'Feminino',
    phone: '',
    email: '',
  });

  useEffect(() => {
    if (patient) {
      setFormData({
        name: patient.name,
        cpf: patient.cpf,
        birthDate: patient.birthDate,
        gender: patient.gender,
        phone: patient.phone,
        email: patient.email,
      });
    }
  }, [patient]);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    
    let recordNumber = patient?.recordNumber;
    if (!recordNumber && !patient) {
      recordNumber = `PR-${(mockPatients.length + 1001).toString()}`;
    }

    onSave({
      id: patient?.id || Math.random().toString(36).substr(2, 9),
      recordNumber,
      ...formData,
    });
  };

  const formatCPF = (value: string) => {
    const numbers = value.replace(/\D/g, '');
    return numbers
      .replace(/(\d{3})(\d)/, '$1.$2')
      .replace(/(\d{3})(\d)/, '$1.$2')
      .replace(/(\d{3})(\d{1,2})/, '$1-$2')
      .replace(/(-\d{2})\d+?$/, '$1');
  };

  const formatPhone = (value: string) => {
    const numbers = value.replace(/\D/g, '');
    if (numbers.length <= 10) {
      return numbers
        .replace(/(\d{2})(\d)/, '($1) $2')
        .replace(/(\d{4})(\d)/, '$1-$2')
        .replace(/(-\d{4})\d+?$/, '$1');
    }
    return numbers
      .replace(/(\d{2})(\d)/, '($1) $2')
      .replace(/(\d{5})(\d)/, '$1-$2')
      .replace(/(-\d{4})\d+?$/, '$1');
  };

  return (
    <div className="fixed inset-0 z-[60] flex items-center justify-center bg-slate-900/60 backdrop-blur-md p-4 animate-in fade-in duration-200">
      <div className="bg-white dark:bg-slate-900 rounded-[2rem] shadow-2xl w-full max-w-lg overflow-hidden flex flex-col max-h-[90vh] border border-white dark:border-slate-800">
        {/* Header */}
        <div className="flex items-center justify-between p-8 border-b border-slate-100 dark:border-slate-800 bg-slate-50/50 dark:bg-slate-900/50">
          <div>
            <div className="flex items-center gap-2">
              <h2 className="text-2xl font-bold text-slate-900 dark:text-white">{patient ? 'Editar Paciente' : 'Novo Paciente'}</h2>
              {patient?.recordNumber && (
                <span className="bg-indigo-100 dark:bg-indigo-900/50 text-indigo-700 dark:text-indigo-400 text-[10px] font-bold px-2 py-0.5 rounded-full uppercase tracking-wider">
                  #{patient.recordNumber}
                </span>
              )}
            </div>
            <p className="text-sm text-slate-500 dark:text-slate-400 mt-1">Prencha as informa├º├Áes cadastrais do paciente</p>
          </div>
          <button 
            onClick={onClose}
            className="p-2 text-slate-400 hover:text-slate-600 dark:hover:text-slate-300 hover:bg-slate-100 dark:hover:bg-slate-800 rounded-full transition-colors"
          >
            <X size={20} />
          </button>
        </div>

        {/* Content */}
        <form onSubmit={handleSubmit} className="flex-1 overflow-y-auto p-8 space-y-6 custom-scrollbar">
          <div className="space-y-4">
            {/* Nome */}
            <div className="space-y-2">
              <label className="text-[10px] font-bold text-slate-400 dark:text-slate-500 uppercase tracking-widest ml-1">Nome Completo</label>
              <div className="relative group">
                <input 
                  type="text" 
                  required
                  value={formData.name}
                  onChange={(e) => setFormData({...formData, name: e.target.value})}
                  className="w-full pl-11 pr-4 py-3 bg-slate-50 dark:bg-slate-800 border border-slate-200 dark:border-slate-700 rounded-2xl text-sm focus:ring-2 focus:ring-indigo-500 focus:bg-white dark:focus:bg-slate-800 outline-none transition-all dark:text-slate-100 dark:placeholder-slate-500"
                  placeholder="Nome do paciente"
                />
                <User className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400 group-focus-within:text-indigo-500 transition-colors" size={18} />
              </div>
            </div>

            {/* CPF & Nascimento */}
            <div className="grid grid-cols-2 gap-4">
              <div className="space-y-2">
                <label className="text-[10px] font-bold text-slate-400 dark:text-slate-500 uppercase tracking-widest ml-1">CPF</label>
                <div className="relative group">
                  <input 
                    type="text" 
                    required
                    value={formData.cpf}
                    onChange={(e) => setFormData({...formData, cpf: formatCPF(e.target.value)})}
                    className="w-full pl-11 pr-4 py-3 bg-slate-50 dark:bg-slate-800 border border-slate-200 dark:border-slate-700 rounded-2xl text-sm focus:ring-2 focus:ring-indigo-500 focus:bg-white dark:focus:bg-slate-800 outline-none transition-all dark:text-slate-100 dark:placeholder-slate-500"
                    placeholder="000.000.000-00"
                  />
                  <CreditCard className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400 group-focus-within:text-indigo-500 transition-colors" size={18} />
                </div>
              </div>
              <div className="space-y-2">
                <label className="text-[10px] font-bold text-slate-400 dark:text-slate-500 uppercase tracking-widest ml-1">Data de Nascimento</label>
                <div className="relative group">
                    <input 
                      type="date" 
                      required
                      value={formData.birthDate}
                      onChange={(e) => setFormData({...formData, birthDate: e.target.value})}
                      className="w-full pl-11 pr-4 py-3 bg-slate-50 dark:bg-slate-800 border border-slate-200 dark:border-slate-700 rounded-2xl text-sm focus:ring-2 focus:ring-indigo-500 focus:bg-white dark:focus:bg-slate-800 outline-none transition-all dark:text-slate-100 dark:[color-scheme:dark]"
                    />
                  <Calendar className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400 group-focus-within:text-indigo-500 transition-colors" size={18} />
                </div>
              </div>
            </div>

            {/* G├¬nero */}
            <div className="space-y-2">
              <label className="text-[10px] font-bold text-slate-400 dark:text-slate-500 uppercase tracking-widest ml-1">G├¬nero</label>
              <CustomSelect 
                options={[
                  { id: 'Feminino', name: 'Feminino' },
                  { id: 'Masculino', name: 'Masculino' },
                  { id: 'Outro', name: 'Outro' },
                ]}
                value={formData.gender}
                onChange={(val) => setFormData({...formData, gender: val})}
              />
            </div>

            {/* Contato */}
            <div className="grid grid-cols-2 gap-4">
              <div className="space-y-2">
                <label className="text-[10px] font-bold text-slate-400 dark:text-slate-500 uppercase tracking-widest ml-1">Telefone</label>
