            >
              Cancelar
            </button>
            <button 
              type="submit"
              className="flex items-center gap-2 px-8 py-3 bg-indigo-600 text-white rounded-2xl text-sm font-bold hover:bg-indigo-700 active:scale-[0.98] transition-all shadow-xl shadow-indigo-100 dark:shadow-none"
            >
              <Save size={18} />
              {patient ? 'Salvar Altera├º├Áes' : 'Cadastrar Paciente'}
            </button>
          </div>
        </form>
      </div>
    </div>
  );
}

'use client';

import React, { useState } from 'react';
import { 
  Calendar, 
  Users, 
  UserRound, 
  User,
  History, 
  PlusCircle,
  Menu,
  X,
  LogOut,
  PanelLeftClose,
  PanelLeftOpen,
  Settings,
  ShieldCheck,
  CreditCard,
  ClipboardList,
  Mail,
  Megaphone,
  ChevronDown,
  BarChart3
} from 'lucide-react';
import { View } from '@/lib/types';
import { cn } from '@/lib/utils';
import { motion, AnimatePresence } from 'motion/react';

interface SidebarProps {
  currentView: View;
  setView: (view: View) => void;
  isOpen: boolean;
  setIsOpen: (isOpen: boolean) => void;
  isCollapsed: boolean;
  setIsCollapsed: (isCollapsed: boolean) => void;
  onOpenProfile: () => void;
  onLogout: () => void;
}

export default function Sidebar({ 
  currentView, 
  setView, 
  isOpen, 
  setIsOpen,
  isCollapsed,
  setIsCollapsed,
  onOpenProfile,
  onLogout
