  const [isUserMenuOpen, setIsUserMenuOpen] = useState(false);
  const menuItems = [
    { id: 'novo-agendamento', label: 'Novo Agendamento', icon: PlusCircle, primary: true },
    { id: 'agenda', label: 'Agenda', icon: Calendar },
