'use client';

import React, { useState } from 'react';
import { 
  ShieldCheck, 
  CreditCard, 
  ClipboardList, 
  Mail, 
  Megaphone,
  Plus,
  Trash2,
  Edit2,
  Check,
  X,
  Lock,
  Eye,
  Settings as SettingsIcon,
  Users as UsersIcon,
  Calendar as CalendarIcon,
  CreditCard as CreditCardIcon,
  Save,
  AlertTriangle,
  ChevronUp,
  ChevronDown,
  Building2,
  MapPin,
  Phone as PhoneIcon,
  Search,
  ExternalLink,
  Info,
  Image as ImageIcon,
  History,
  CheckCircle,
  Calendar,
  Upload,
  Zap,
  Activity,
  Globe,
  Database,
  Link2,
  ChevronLeft,
  ChevronRight,
  Filter,
  UserPlus
} from 'lucide-react';
import { format, differenceInMonths, subMonths } from 'date-fns';
import { ptBR } from 'date-fns/locale';
import { cn, normalizeString } from '@/lib/utils';
import { mockUnits, mockAppointments, mockScheduleConfigs, mockScheduleBlocks, mockPatients, mockProcedures, mockSystemSettings, mockDoctors, mockInsurances } from '@/lib/mockData';
import { View } from '@/lib/types';
import { toast } from 'react-toastify';
import ImportProceduresModal from './ImportProceduresModal';
import ImportInsurancesModal from './ImportInsurancesModal';

type SettingTab = 'perfis' | 'convenios' | 'procedimentos' | 'parametros' | 'mala-direta' | 'campanha';

export default function SystemSettings({ searchQuery = '', setView }: { searchQuery?: string, setView?: (view: View) => void }) {
  const [activeTab, setActiveTab] = useState<SettingTab>('parametros');
  
  // Persistent state for modules
  const [procedures, setProcedures] = useState<any[]>([...mockProcedures]);
  const [globalSettings, setGlobalSettings] = useState({
    ...JSON.parse(JSON.stringify(mockSystemSettings)),
    unidades: [...mockUnits]
  });
  const [insurances, setInsurances] = useState([...mockInsurances]);

  const handleProceduresSave = (data: any, editingProcedure?: any) => {
    if (editingProcedure) {
      const newProcedures = procedures.map(p => p.id === editingProcedure.id ? { ...p, ...data } : p);
      setProcedures(newProcedures);
      // Synchronize with mockData
      mockProcedures.length = 0;
      mockProcedures.push(...newProcedures);
      toast.success('Procedimento atualizado!');
    } else {
      const newProcedure = { id: Date.now().toString(), ...data };
      const newProcedures = [...procedures, newProcedure];
      setProcedures(newProcedures);
      // Synchronize with mockData
      mockProcedures.length = 0;
      mockProcedures.push(...newProcedures);
      toast.success('Procedimento criado!');
    }
  };

  const handleProceduresDelete = (itemToRemove: any) => {
    const newProcedures = procedures.filter(p => p.id !== itemToRemove.id);
    setProcedures(newProcedures);
    mockProcedures.length = 0;
    mockProcedures.push(...newProcedures);
  };

  const handleImportProcedures = (imported: any[]) => {
    const newProcedures = [...procedures, ...imported];
    setProcedures(newProcedures);
    mockProcedures.length = 0;
    mockProcedures.push(...newProcedures);
  };

  const handleImportInsurances = (imported: any[]) => {
    const newInsurances = [...insurances, ...imported];
    setInsurances(newInsurances);
    mockInsurances.length = 0;
    mockInsurances.push(...newInsurances);
  };

  const handleInsurancesSave = (data: any, editingInsurance?: any) => {
    let newInsurances;
    if (editingInsurance) {
      newInsurances = insurances.map(i => i.id === editingInsurance.id ? { ...i, ...data } : i);
      toast.success('Conv├¬nio atualizado!');
    } else {
      const newInsurance = { id: Date.now(), ...data, patients: 0 };
      newInsurances = [...insurances, newInsurance];
      toast.success('Conv├¬nio criado com sucesso!');
    }
    setInsurances(newInsurances);
    mockInsurances.length = 0;
    mockInsurances.push(...newInsurances);
  };

  const handleInsurancesDelete = (itemToRemove: any) => {
    const newInsurances = insurances.filter(i => i.id !== itemToRemove.id);
    setInsurances(newInsurances);
    mockInsurances.length = 0;
    mockInsurances.push(...newInsurances);
  };

  const tabs: { id: SettingTab; label: string; icon: any }[] = [
    { id: 'parametros', label: 'Par├ómetros', icon: SettingsIcon },
    { id: 'perfis', label: 'Perfis de Acesso', icon: ShieldCheck },
    { id: 'convenios', label: 'Conv├¬nios', icon: CreditCard },
    { id: 'procedimentos', label: 'Procedimentos', icon: ClipboardList },
    { id: 'mala-direta', label: 'Mala Direta', icon: Mail },
    { id: 'campanha', label: 'Campanha', icon: Megaphone },
  ];

  const renderContent = () => {
    switch (activeTab) {
      case 'perfis':
        return <AccessProfiles searchQuery={searchQuery} />;
      case 'procedimentos':
        return <Procedures 
          searchQuery={searchQuery} 
          procedures={procedures} 
          onSave={handleProceduresSave}
          onDelete={handleProceduresDelete}
          onImport={handleImportProcedures}
        />;
      case 'convenios':
        return <Insurances 
          searchQuery={searchQuery} 
          insurances={insurances}
          onSave={handleInsurancesSave}
          onDelete={handleInsurancesDelete}
          onImport={handleImportInsurances}
        />;
      case 'parametros':
        return <SystemParameters 
          setView={setView} 
          settings={globalSettings}
          setSettings={setGlobalSettings}
        />;
      case 'mala-direta':
        return <MalaDireta searchQuery={searchQuery} />;
      case 'campanha':
        return <Campanhas searchQuery={searchQuery} />;
      default:
        return (
          <div className="flex flex-col items-center justify-center py-20 bg-white dark:bg-slate-900 rounded-3xl border border-dashed border-slate-200 dark:border-slate-800">
            <div className="w-16 h-16 bg-slate-50 dark:bg-slate-800 rounded-2xl flex items-center justify-center text-slate-300 dark:text-slate-600 mb-4">
              {React.createElement(tabs.find(t => t.id === activeTab)?.icon, { size: 32 })}
            </div>
            <h3 className="text-lg font-bold text-slate-900 dark:text-white mb-2">Em breve</h3>
            <p className="text-sm text-slate-500 dark:text-slate-400 max-w-xs text-center">
              Esta funcionalidade de {tabs.find(t => t.id === activeTab)?.label} est├í em desenvolvimento e estar├í dispon├¡vel em breve.
            </p>
          </div>
        );
    }
  };

  return (
    <div className="max-w-6xl mx-auto space-y-6">
      {/* Tab Navigation */}
      <div className="flex flex-wrap gap-2 bg-white/50 dark:bg-slate-900/50 p-2 rounded-2xl border border-slate-200/60 dark:border-slate-800 backdrop-blur-sm">
        {tabs.map((tab) => (
          <button
            key={tab.id}
            onClick={() => setActiveTab(tab.id)}
            className={cn(
              "flex items-center gap-2 px-4 py-2.5 rounded-xl text-sm font-bold transition-all",
              activeTab === tab.id 
                ? "bg-indigo-600 text-white shadow-lg shadow-indigo-100 dark:shadow-none" 
                : "text-slate-500 dark:text-slate-400 hover:bg-white dark:hover:bg-slate-800 hover:text-slate-900 dark:hover:text-slate-100"
            )}
          >
            <tab.icon size={18} />
            {tab.label}
          </button>
        ))}
      </div>

      {/* Tab Content */}
      <div className="animate-in fade-in slide-in-from-bottom-2 duration-300">
        {renderContent()}
      </div>
    </div>
  );
}

function AccessProfiles({ searchQuery = '' }: { searchQuery: string }) {
  const [profiles, setProfiles] = useState([
    { id: 1, name: 'Administrador', permissions: ['Total'], color: 'bg-indigo-500' },
    { id: 2, name: 'M├®dico', permissions: ['Agenda', 'Hist├│rico'], color: 'bg-emerald-500' },
    { id: 3, name: 'Recep├º├úo', permissions: ['Agenda', 'Pacientes'], color: 'bg-sky-500' },
    { id: 4, name: 'Enfermagem', permissions: ['Agenda', 'Procedimentos'], color: 'bg-rose-500' },
  ]);

  const filteredProfiles = profiles.filter(p => {
    const search = normalizeString(searchQuery);
    return normalizeString(p.name).includes(search);
  });

  const [selectedProfile, setSelectedProfile] = useState<any>(null);
  const [itemToDelete, setItemToDelete] = useState<any>(null);
  const [profileFormOpen, setProfileFormOpen] = useState(false);
  const [profileToEdit, setProfileToEdit] = useState<any>(null);

  const confirmDelete = () => {
    const itemToRemove = itemToDelete;
    const previousProfiles = [...profiles];
    setProfiles(profiles.filter(p => p.id !== itemToRemove.id));
    
    toast.info(
      <div className="flex items-center justify-between gap-2 w-full overflow-hidden">
        <span className="text-[11px] font-medium truncate min-w-0">
          Perfil <strong>{itemToRemove.name}</strong> exclu├¡do
        </span>
        <button 
          onClick={() => {
            setProfiles(previousProfiles);
            toast.dismiss();
            toast.success('Exclus├úo desfeita!');
          }}
          className="shrink-0 px-3 py-1 bg-white text-indigo-600 rounded-lg text-[10px] font-bold shadow-sm hover:bg-indigo-50 transition-colors whitespace-nowrap"
        >
          DESFAZER
        </button>
      </div>,
      { 
        icon: Trash2,
        autoClose: 5000,
        closeOnClick: false
      }
    );
    setItemToDelete(null);
  };

  const handleSavePermissions = (profileId: number, newPermissions: string[]) => {
    setProfiles(profiles.map(p => p.id === profileId ? { ...p, permissions: newPermissions } : p));
    toast.success('Permiss├Áes atualizadas com sucesso!');
    setSelectedProfile(null);
  };

  const handleSaveProfile = (data: any) => {
    if (profileToEdit) {
      setProfiles(profiles.map(p => p.id === profileToEdit.id ? { ...p, ...data } : p));
      toast.success('Perfil atualizado com sucesso!');
    } else {
      const newProfile = {
        id: Date.now(),
        ...data,
        permissions: ['Agenda'] // Default permission
      };
      setProfiles([...profiles, newProfile]);
      toast.success('Novo perfil de acesso criado!');
    }
    setProfileFormOpen(false);
    setProfileToEdit(null);
  };

  return (
    <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
      {filteredProfiles.map((profile) => (
        <div key={profile.id} className="bg-white dark:bg-slate-900 p-6 rounded-[2rem] border border-slate-100 dark:border-slate-800 shadow-sm hover:shadow-md transition-all group">
          <div className="flex justify-between items-start mb-6">
            <div className="flex gap-4 items-center">
              <div className={cn("w-12 h-12 rounded-2xl flex items-center justify-center text-white font-bold text-xl shadow-lg shadow-black/5", profile.color)}>
                {profile.name.charAt(0)}
              </div>
              <div>
                <h4 className="font-bold text-slate-900 dark:text-slate-100 text-lg">{profile.name}</h4>
                <p className="text-xs text-slate-400 dark:text-slate-500 font-medium uppercase tracking-widest mt-0.5">Perfil de Acesso</p>
              </div>
            </div>
            <div className="flex items-center gap-2 opacity-0 group-hover:opacity-100 transition-opacity">
              <button 
                onClick={() => {
                  setProfileToEdit(profile);
                  setProfileFormOpen(true);
                }}
                className="p-2 hover:bg-slate-100 dark:hover:bg-slate-800 rounded-xl text-slate-400 dark:text-slate-600 transition-colors"
                title="Editar Nome/Cor"
              >
                <Edit2 size={16} />
              </button>
              <button 
                onClick={() => setItemToDelete({ id: profile.id, name: profile.name, type: 'perfil' })}
                className="p-2 hover:bg-red-50 dark:hover:bg-red-900/30 rounded-xl text-red-400 dark:text-red-500 transition-colors"
              >
                <Trash2 size={16} />
              </button>
            </div>
          </div>
          
          <div className="space-y-4">
            <p className="text-xs font-bold text-slate-400 dark:text-slate-500 uppercase tracking-widest">Permiss├Áes Habilitadas</p>
            <div className="flex flex-wrap gap-2">
              {profile.permissions.map((perm, i) => (
                <span key={i} className="px-3 py-1.5 bg-slate-50 dark:bg-slate-800 text-slate-600 dark:text-slate-400 rounded-lg text-[10px] font-bold border border-slate-100 dark:border-slate-700 flex items-center gap-1.5">
                  <Check size={12} className="text-emerald-500" /> {perm}
                </span>
              ))}
              <button 
                onClick={() => setSelectedProfile(profile)}
                className="px-3 py-1.5 bg-white dark:bg-slate-800 text-indigo-600 dark:text-indigo-400 border border-indigo-100 dark:border-indigo-900/50 rounded-lg text-[10px] font-bold hover:bg-indigo-50 dark:hover:bg-slate-700 transition-colors"
              >
                + Editar Permiss├Áes
              </button>
            </div>
          </div>
        </div>
      ))}
      {filteredProfiles.length === 0 && (
        <div className="md:col-span-2 p-12 text-center bg-white dark:bg-slate-900 rounded-3xl border border-slate-100 dark:border-slate-800 italic text-slate-400 dark:text-slate-500 text-sm">
          Nenhum perfil encontrado para "{searchQuery}"
        </div>
      )}
      <button 
        onClick={() => {
          setProfileToEdit(null);
          setProfileFormOpen(true);
        }}
        className="group relative flex flex-col items-center justify-center p-8 rounded-[2rem] border-2 border-dashed border-slate-200 dark:border-slate-800 hover:border-indigo-400 dark:hover:border-indigo-600 transition-all bg-white dark:bg-slate-900 hover:bg-indigo-50/30 dark:hover:bg-indigo-900/10 min-h-[160px]"
      >
        <div className="w-12 h-12 bg-slate-100 dark:bg-slate-800 rounded-2xl flex items-center justify-center text-slate-400 dark:text-slate-600 mb-3 group-hover:bg-indigo-600 group-hover:text-white transition-all">
          <Plus size={24} />
        </div>
        <p className="text-sm font-bold text-slate-500 dark:text-slate-400 group-hover:text-indigo-600 dark:group-hover:text-indigo-400 transition-colors">Novo Perfil de Acesso</p>
      </button>

      {selectedProfile && (
        <PermissionsModal 
          profile={selectedProfile}
          onClose={() => setSelectedProfile(null)}
          onSave={handleSavePermissions}
        />
      )}

      {profileFormOpen && (
        <ProfileModal 
          profile={profileToEdit}
          onClose={() => setProfileFormOpen(false)}
          onSave={handleSaveProfile}
        />
      )}

      {itemToDelete && (
        <DeleteConfirmationModal 
          itemName={itemToDelete.name}
          itemType={itemToDelete.type}
          onClose={() => setItemToDelete(null)}
          onConfirm={confirmDelete}
        />
      )}
    </div>
  );
}

function PermissionsModal({ profile, onClose, onSave }: { profile: any, onClose: () => void, onSave: (id: number, perms: string[]) => void }) {
  const categories = [
    {
      id: 'agenda',
      label: 'Agenda',
      icon: CalendarIcon,
      perms: [
        { id: 'view_agenda', label: 'Visualizar Agenda' },
        { id: 'create_apt', label: 'Agendar Pacientes' },
        { id: 'edit_apt', label: 'Editar Agendamentos' },
        { id: 'cancel_apt', label: 'Cancelar Agendamentos' },
        { id: 'transfer_apt', label: 'Transferir Atendimento' },
        { id: 'manage_blocks', label: 'Bloquear Agenda' },
        { id: 'view_reports', label: 'Ver Relat├│rios' },
      ]
    },
    {
      id: 'pacientes',
      label: 'Pacientes',
      icon: UsersIcon,
      perms: [
        { id: 'view_patients', label: 'Visualizar Pacientes' },
        { id: 'create_patient', label: 'Cadastrar Novo Paciente' },
        { id: 'edit_patient', label: 'Editar Dados cadastrais' },
        { id: 'view_history', label: 'Ver Prontu├írio/Hist├│rico' },
        { id: 'delete_patient', label: 'Excluir Paciente' },
      ]
    },
    {
      id: 'profissionais',
      label: 'Corpo Cl├¡nico',
      icon: ShieldCheck,
      perms: [
        { id: 'view_docs', label: 'Visualizar M├®dicos' },
        { id: 'create_doc', label: 'Cadastrar Novo M├®dico' },
        { id: 'edit_doc', label: 'Editar Escalas' },
        { id: 'delete_doc', label: 'Excluir Profissional' },
      ]
    },
    {
      id: 'financeiro',
      label: 'Financeiro',
      icon: CreditCardIcon,
      perms: [
        { id: 'view_billing', label: 'Ver Faturamento' },
        { id: 'manage_insurances', label: 'Gerenciar Conv├¬nios' },
        { id: 'manage_procedures', label: 'Gerenciar Procedimentos' },
      ]
    },
    {
      id: 'configuracoes',
      label: 'Configura├º├Áes',
      icon: SettingsIcon,
      perms: [
        { id: 'system_settings', label: 'Configura├º├Áes do Sistema' },
        { id: 'access_profiles', label: 'Gerenciar Perfis de Acesso' },
        { id: 'audit_logs', label: 'Ver Logs de Auditoria' },
      ]
    }
  ];

  const [selectedPerms, setSelectedPerms] = useState<string[]>(
    profile.permissions.includes('Total') 
      ? categories.flatMap(c => c.perms.map(p => p.label))
      : profile.permissions
  );

  const togglePerm = (label: string) => {
    if (selectedPerms.includes(label)) {
      setSelectedPerms(selectedPerms.filter(p => p !== label));
    } else {
      setSelectedPerms([...selectedPerms, label]);
    }
  };

  return (
    <div className="fixed inset-0 z-[120] flex items-center justify-center bg-slate-900/60 dark:bg-slate-950/80 backdrop-blur-md p-4 animate-in fade-in duration-300">
      <div className="bg-white dark:bg-slate-900 rounded-[3rem] shadow-2xl w-full max-w-5xl max-h-[90vh] overflow-hidden flex flex-col border border-white dark:border-slate-800 animate-in zoom-in-95 duration-200">
        <div className="p-8 border-b border-slate-50 dark:border-slate-800 flex justify-between items-center bg-slate-50/30 dark:bg-slate-900/50">
          <div className="flex items-center gap-4">
            <div className={cn("w-12 h-12 rounded-2xl flex items-center justify-center text-white font-bold text-xl shadow-lg dark:shadow-none font-sans", profile.color)}>
              {profile.name.charAt(0)}
            </div>
            <div>
              <h2 className="text-xl font-bold text-slate-900 dark:text-white">Editar Permiss├Áes: {profile.name}</h2>
              <p className="text-xs text-slate-500 dark:text-slate-400 font-medium uppercase tracking-widest mt-0.5">Defina o que este perfil pode acessar</p>
            </div>
          </div>
          <button onClick={onClose} className="p-2 text-slate-400 hover:text-slate-600 dark:hover:text-slate-300 hover:bg-white dark:hover:bg-slate-800 rounded-full transition-all border border-transparent hover:border-slate-100 dark:hover:border-slate-700">
            <X size={20} />
          </button>
        </div>

        <div className="flex-1 overflow-y-auto p-8 pt-6 space-y-8">
          {categories.map((cat) => {
            const Icon = cat.icon;
            const allSelected = cat.perms.every(p => selectedPerms.includes(p.label));
            
            return (
              <div key={cat.id} className="space-y-4">
                <div className="flex items-center justify-between px-2">
                  <div className="flex items-center gap-2">
                    <div className="w-8 h-8 rounded-lg bg-indigo-50 dark:bg-indigo-900/30 text-indigo-600 dark:text-indigo-400 flex items-center justify-center">
                      <Icon size={16} />
                    </div>
                    <h3 className="font-bold text-slate-800 dark:text-slate-200 uppercase tracking-widest text-[11px]">{cat.label}</h3>
                  </div>
                    <button 
                    onClick={() => {
                      if (allSelected) {
                        setSelectedPerms(selectedPerms.filter(p => !cat.perms.map(cp => cp.label).includes(p)));
                      } else {
                        const newPerms = [...selectedPerms];
                        cat.perms.forEach(p => {
                          if (!newPerms.includes(p.label)) newPerms.push(p.label);
                        });
                        setSelectedPerms(newPerms);
                      }
                    }}
                    className="text-[10px] font-bold text-indigo-600 dark:text-indigo-400 hover:underline"
                  >
                    {allSelected ? 'Desmarcar todos' : 'Marcar todos'}
                  </button>
                </div>

                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-3">
                  {cat.perms.map((perm) => (
                    <button
                      key={perm.id}
                      onClick={() => togglePerm(perm.label)}
                      className={cn(
                        "flex items-center justify-between p-4 rounded-2xl border transition-all text-left",
                        selectedPerms.includes(perm.label)
                          ? "bg-indigo-50/50 dark:bg-indigo-900/20 border-indigo-200 dark:border-indigo-900/50 ring-1 ring-indigo-200 dark:ring-indigo-900/50 shadow-sm"
                          : "bg-white dark:bg-slate-900 border-slate-100 dark:border-slate-800 hover:bg-slate-50 dark:hover:bg-slate-800"
                      )}
                    >
                      <span className={cn(
                        "text-xs font-semibold",
                        selectedPerms.includes(perm.label) ? "text-indigo-700 dark:text-indigo-300" : "text-slate-600 dark:text-slate-400"
                      )}>
                        {perm.label}
                      </span>
                      <div className={cn(
                        "w-5 h-5 rounded-md border flex items-center justify-center transition-all",
                        selectedPerms.includes(perm.label)
                          ? "bg-indigo-600 border-indigo-600 text-white"
                          : "border-slate-200 dark:border-slate-700 bg-slate-50 dark:bg-slate-800"
                      )}>
                        {selectedPerms.includes(perm.label) && <Check size={12} />}
                      </div>
                    </button>
                  ))}
                </div>
              </div>
            );
          })}
        </div>

        <div className="p-8 border-t border-slate-50 dark:border-slate-800 bg-slate-50/10 dark:bg-slate-900/10 flex justify-end gap-3">
          <button onClick={onClose} className="px-6 py-3 bg-white dark:bg-slate-800 border border-slate-200 dark:border-slate-700 text-slate-600 dark:text-slate-400 rounded-2xl text-sm font-bold hover:bg-slate-50 dark:hover:bg-slate-700 transition-all">
            Cancelar
          </button>
          <button 
            onClick={() => onSave(profile.id, selectedPerms)}
            className="px-8 py-3 bg-indigo-600 text-white rounded-2xl text-sm font-bold hover:bg-indigo-700 shadow-xl shadow-indigo-100 dark:shadow-none transition-all active:scale-[0.98]"
          >
            Salvar Altera├º├Áes
          </button>
        </div>
      </div>
    </div>
  );
}

function Insurances({ 
  searchQuery = '',
  insurances,
  onSave,
  onDelete,
  onImport
}: { 
  searchQuery: string,
  insurances: any[],
  onSave: (data: any, editingInsurance?: any) => void,
  onDelete: (item: any) => void,
  onImport: (imported: any[]) => void
}) {
  const [showImportModal, setShowImportModal] = useState(false);
  const [currentPage, setCurrentPage] = useState(1);
  const itemsPerPage = 10;

  const [sortConfig, setSortConfig] = useState<{ key: string; direction: 'asc' | 'desc' } | null>(null);

  const handleSort = (key: string) => {
    let direction: 'asc' | 'desc' = 'asc';
    if (sortConfig && sortConfig.key === key && sortConfig.direction === 'asc') {
      direction = 'desc';
    }
    setSortConfig({ key, direction });
  };

  const filteredInsurances = insurances.filter(i => {
    const search = normalizeString(searchQuery);
    return normalizeString(i.name).includes(search);
  }).sort((a: any, b: any) => {
    if (!sortConfig) return 0;
    const { key, direction } = sortConfig;
    if (a[key] < b[key]) return direction === 'asc' ? -1 : 1;
    if (a[key] > b[key]) return direction === 'asc' ? 1 : -1;
    return 0;
  });

  const totalPages = Math.ceil(filteredInsurances.length / itemsPerPage);
  const paginatedInsurances = filteredInsurances.slice(
    (currentPage - 1) * itemsPerPage,
    currentPage * itemsPerPage
  );

  // Reset to first page when searching
  React.useEffect(() => {
    setCurrentPage(1);
  }, [searchQuery]);

  const [modalOpen, setModalOpen] = useState(false);
  const [editingInsurance, setEditingInsurance] = useState<any>(null);
  const [itemToDelete, setItemToDelete] = useState<any>(null);

  const handleSave = (data: any) => {
    onSave(data, editingInsurance);
    setModalOpen(false);
    setEditingInsurance(null);
  };

  const confirmDelete = () => {
    onDelete(itemToDelete);
    setItemToDelete(null);
  };

  return (
    <div className="bg-white dark:bg-slate-900 rounded-[2rem] border border-slate-100 dark:border-slate-800 shadow-sm overflow-hidden">
      <div className="p-6 border-b border-slate-50 dark:border-slate-800 bg-slate-50/30 dark:bg-slate-900/50 flex justify-between items-center">
        <h3 className="font-bold text-slate-900 dark:text-white">Conv├¬nios Ativos</h3>
        <div className="flex items-center gap-3">
          <button 
            onClick={() => setShowImportModal(true)}
            className="flex items-center justify-center gap-2 px-4 py-2 bg-white dark:bg-slate-800 text-indigo-600 dark:text-indigo-400 border border-indigo-100 dark:border-indigo-900/50 rounded-xl text-xs font-bold hover:bg-indigo-50 dark:hover:bg-slate-700 transition-all shadow-sm active:scale-[0.98]"
          >
            <Upload size={14} />
            Importar Lista
          </button>
          <button 
            onClick={() => {
              setEditingInsurance(null);
              setModalOpen(true);
            }}
            className="flex items-center gap-2 px-4 py-2 bg-indigo-600 text-white rounded-xl text-xs font-bold hover:bg-indigo-700 shadow-lg shadow-indigo-100 dark:shadow-none transition-all active:scale-[0.98]"
          >
            <Plus size={16} /> Novo Conv├¬nio
          </button>
        </div>
      </div>
      <div className="overflow-x-auto">
        <table className="w-full text-left">
          <thead>
            <tr className="bg-slate-50/50 dark:bg-slate-900/50 border-b border-slate-100 dark:border-slate-800">
              <th 
                className="px-6 py-4 text-[10px] uppercase tracking-widest font-bold text-slate-400 dark:text-slate-500 cursor-pointer hover:text-indigo-600 dark:hover:text-indigo-400 transition-colors"
                onClick={() => handleSort('name')}
              >
                <div className="flex items-center gap-2">
                  Nome do Conv├¬nio
                  {sortConfig?.key === 'name' && (
                    sortConfig.direction === 'asc' ? <ChevronUp size={14} /> : <ChevronDown size={14} />
                  )}
                </div>
              </th>
              <th 
                className="px-6 py-4 text-[10px] uppercase tracking-widest font-bold text-slate-400 dark:text-slate-500 cursor-pointer hover:text-indigo-600 dark:hover:text-indigo-400 transition-colors"
                onClick={() => handleSort('status')}
              >
                <div className="flex items-center gap-2">
                  Status
                  {sortConfig?.key === 'status' && (
                    sortConfig.direction === 'asc' ? <ChevronUp size={14} /> : <ChevronDown size={14} />
                  )}
                </div>
              </th>
              <th 
                className="px-6 py-4 text-[10px] uppercase tracking-widest font-bold text-slate-400 dark:text-slate-500 cursor-pointer hover:text-indigo-600 dark:hover:text-indigo-400 transition-colors"
                onClick={() => handleSort('patients')}
              >
                <div className="flex items-center gap-2">
                  Pacientes
                  {sortConfig?.key === 'patients' && (
                    sortConfig.direction === 'asc' ? <ChevronUp size={14} /> : <ChevronDown size={14} />
                  )}
                </div>
              </th>
              <th className="px-6 py-4 text-[10px] uppercase tracking-widest font-bold text-slate-400 dark:text-slate-500 text-right">A├º├Áes</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-50 dark:divide-slate-800">
            {paginatedInsurances.map((ins) => (
              <tr key={ins.id} className="hover:bg-slate-50/80 dark:hover:bg-slate-800/50 transition-colors">
                <td className="px-6 py-4 font-bold text-slate-700 dark:text-slate-200 text-sm">{ins.name}</td>
                <td className="px-6 py-4">
                  <span className={cn(
                    "px-2.5 py-1 rounded-lg text-[10px] font-bold border uppercase",
                    ins.status === 'Ativo' ? "bg-emerald-50 dark:bg-emerald-900/30 text-emerald-600 dark:text-emerald-400 border-emerald-100 dark:border-emerald-800" : "bg-slate-50 dark:bg-slate-800 text-slate-400 dark:text-slate-500 border-slate-100 dark:border-slate-700"
                  )}>
                    {ins.status}
                  </span>
                </td>
                <td className="px-6 py-4 text-xs text-slate-500 dark:text-slate-400 font-medium">{ins.patients} pacientes vinculados</td>
                <td className="px-6 py-4 text-right">
                  <div className="flex items-center justify-end gap-1">
                    <button 
                      onClick={() => {
                        setEditingInsurance(ins);
                        setModalOpen(true);
                      }}
                      className="p-2 hover:bg-white dark:hover:bg-slate-700 rounded-lg text-slate-400 dark:text-slate-500 transition-all border border-transparent hover:border-slate-100 dark:hover:border-slate-600"
                    >
                      <Edit2 size={14} />
                    </button>
                    <button 
                      onClick={() => setItemToDelete({ id: ins.id, name: ins.name, type: 'conv├¬nio' })}
                      className="p-2 hover:bg-white dark:hover:bg-slate-700 rounded-lg text-red-400 dark:text-red-500 transition-all border border-transparent hover:border-slate-100 dark:hover:border-slate-600"
                    >
                      <Trash2 size={14} />
                    </button>
                  </div>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
        {filteredInsurances.length === 0 && (
          <div className="p-12 text-center text-slate-400 italic text-sm">
            Nenhum conv├¬nio encontrado para "{searchQuery}"
          </div>
        )}

        {/* Pagination Controls */}
        {totalPages > 1 && (
          <div className="flex flex-col sm:flex-row items-center justify-between gap-4 p-6 border-t border-slate-50 dark:border-slate-800 bg-slate-50/10 dark:bg-slate-900/10">
            <p className="text-[10px] text-slate-400 dark:text-slate-500 font-bold uppercase tracking-widest">
              Mostrando <span className="text-slate-600 dark:text-slate-300">{paginatedInsurances.length}</span> de <span className="text-slate-600 dark:text-slate-300">{filteredInsurances.length}</span> conv├¬nios
            </p>
            
            <div className="flex items-center gap-2">
              <button 
                disabled={currentPage === 1}
                onClick={() => setCurrentPage(prev => Math.max(1, prev - 1))}
                className="w-10 h-10 rounded-xl border border-slate-200 flex items-center justify-center text-slate-400 hover:bg-white hover:text-indigo-600 disabled:opacity-30 disabled:hover:bg-transparent transition-all shadow-sm"
              >
                <ChevronLeft size={18} />
              </button>
              
              <div className="flex items-center gap-1">
                {Array.from({ length: totalPages }, (_, i) => i + 1)
                  .filter(page => {
                    return page === 1 || page === totalPages || Math.abs(page - currentPage) <= 1;
                  })
                  .map((page, index, array) => (
                    <React.Fragment key={page}>
                      {index > 0 && array[index - 1] !== page - 1 && (
                        <span className="text-slate-300 px-1 font-bold">...</span>
                      )}
                      <button 
                        onClick={() => setCurrentPage(page)}
                        className={cn(
                          "w-10 h-10 rounded-xl text-xs font-bold transition-all",
                          currentPage === page 
                            ? "bg-indigo-600 text-white shadow-lg shadow-indigo-100" 
                            : "text-slate-400 hover:bg-white hover:text-slate-600 border border-slate-100 hover:border-slate-200"
                        )}
                      >
                        {page}
                      </button>
                    </React.Fragment>
                  ))}
              </div>

              <button 
                disabled={currentPage === totalPages}
                onClick={() => setCurrentPage(prev => Math.min(totalPages, prev + 1))}
                className="w-10 h-10 rounded-xl border border-slate-200 flex items-center justify-center text-slate-400 hover:bg-white hover:text-indigo-600 disabled:opacity-30 disabled:hover:bg-transparent transition-all shadow-sm"
              >
                <ChevronRight size={18} />
              </button>
            </div>
          </div>
        )}
      </div>

      {modalOpen && (
        <InsuranceModal 
          insurance={editingInsurance}
          onClose={() => setModalOpen(false)}
          onSave={handleSave}
        />
      )}

      {itemToDelete && (
        <DeleteConfirmationModal 
          itemName={itemToDelete.name}
          itemType={itemToDelete.type}
          onClose={() => setItemToDelete(null)}
          onConfirm={confirmDelete}
        />
      )}

      {showImportModal && (
        <ImportInsurancesModal 
          onClose={() => setShowImportModal(false)}
          onImport={onImport}
          existingInsurances={insurances}
        />
      )}
    </div>
  );
}

function Procedures({ 
  searchQuery = '', 
  procedures, 
  onSave, 
  onDelete,
  onImport
}: { 
  searchQuery: string, 
  procedures: any[], 
  onSave: (data: any, editingProcedure?: any) => void,
  onDelete: (item: any) => void,
  onImport: (imported: any[]) => void
}) {
  const [showImportModal, setShowImportModal] = useState(false);
  const [currentPage, setCurrentPage] = useState(1);
  const itemsPerPage = 10;

  const [sortConfig, setSortConfig] = useState<{ key: string; direction: 'asc' | 'desc' } | null>(null);

  const handleSort = (key: string) => {
    let direction: 'asc' | 'desc' = 'asc';
    if (sortConfig && sortConfig.key === key && sortConfig.direction === 'asc') {
      direction = 'desc';
    }
    setSortConfig({ key, direction });
  };

  const filteredProcedures = procedures.filter(p => {
    const search = normalizeString(searchQuery);
    return normalizeString(p.name).includes(search) ||
           normalizeString(p.modality).includes(search);
  }).sort((a: any, b: any) => {
    if (!sortConfig) return 0;
    const { key, direction } = sortConfig;
    const valA = key === 'price' ? parseFloat(a[key]) : a[key];
    const valB = key === 'price' ? parseFloat(b[key]) : b[key];
    if (valA < valB) return direction === 'asc' ? -1 : 1;
    if (valA > valB) return direction === 'asc' ? 1 : -1;
    return 0;
  });

  const totalPages = Math.ceil(filteredProcedures.length / itemsPerPage);
  const paginatedProcedures = filteredProcedures.slice(
    (currentPage - 1) * itemsPerPage,
    currentPage * itemsPerPage
  );

  // Reset to first page when searching
  React.useEffect(() => {
    setCurrentPage(1);
  }, [searchQuery]);

  const [modalOpen, setModalOpen] = useState(false);
  const [editingProcedure, setEditingProcedure] = useState<any>(null);
  const [itemToDelete, setItemToDelete] = useState<any>(null);

  const handleSave = (data: any) => {
    onSave(data, editingProcedure);
    setModalOpen(false);
    setEditingProcedure(null);
  };

  const confirmDelete = () => {
    onDelete(itemToDelete);
    setItemToDelete(null);
  };

  return (
    <div className="space-y-6">
      <div className="bg-white dark:bg-slate-900 rounded-[2rem] border border-slate-100 dark:border-slate-800 shadow-sm overflow-hidden">
        <div className="p-6 border-b border-slate-50 dark:border-slate-800 bg-slate-50/30 dark:bg-slate-900/50 flex justify-between items-center">
          <h3 className="font-bold text-slate-900 dark:text-white">Procedimentos</h3>
          <div className="flex items-center gap-3">
            <button 
              onClick={() => setShowImportModal(true)}
              className="flex items-center justify-center gap-2 px-4 py-2 bg-white dark:bg-slate-800 text-indigo-600 dark:text-indigo-400 border border-indigo-100 dark:border-indigo-900/50 rounded-xl text-xs font-bold hover:bg-indigo-50 dark:hover:bg-slate-700 transition-all shadow-sm active:scale-[0.98]"
            >
              <Upload size={14} />
              Importar Lista
            </button>
            <button 
              onClick={() => {
                setEditingProcedure(null);
                setModalOpen(true);
              }}
              className="flex items-center gap-2 px-4 py-2 bg-indigo-600 text-white rounded-xl text-xs font-bold hover:bg-indigo-700 shadow-lg shadow-indigo-100 dark:shadow-none transition-all active:scale-[0.98]"
            >
              <Plus size={16} /> Novo Procedimento
            </button>
          </div>
        </div>
        <div className="overflow-x-auto">
          <table className="w-full text-left">
            <thead>
              <tr className="bg-slate-50/50 dark:bg-slate-800/50 border-b border-slate-100 dark:border-slate-800">
                <th 
                  className="px-6 py-4 text-[10px] uppercase tracking-widest font-bold text-slate-400 dark:text-slate-500 cursor-pointer hover:text-indigo-600 dark:hover:text-indigo-400 transition-colors"
                  onClick={() => handleSort('name')}
                >
                  <div className="flex items-center gap-2">
                    Procedimento
                    {sortConfig?.key === 'name' && (
                      sortConfig.direction === 'asc' ? <ChevronUp size={14} /> : <ChevronDown size={14} />
                    )}
                  </div>
                </th>
                <th 
                  className="px-6 py-4 text-[10px] uppercase tracking-widest font-bold text-slate-400 dark:text-slate-500 cursor-pointer hover:text-indigo-600 dark:hover:text-indigo-400 transition-colors"
                  onClick={() => handleSort('modality')}
                >
                  <div className="flex items-center gap-2">
                    Modalidade
                    {sortConfig?.key === 'modality' && (
                      sortConfig.direction === 'asc' ? <ChevronUp size={14} /> : <ChevronDown size={14} />
                    )}
                  </div>
                </th>
                <th 
                  className="px-6 py-4 text-[10px] uppercase tracking-widest font-bold text-slate-400 dark:text-slate-500 cursor-pointer hover:text-indigo-600 dark:hover:text-indigo-400 transition-colors"
                  onClick={() => handleSort('price')}
                >
                  <div className="flex items-center gap-2">
                    Valor
                    {sortConfig?.key === 'price' && (
                      sortConfig.direction === 'asc' ? <ChevronUp size={14} /> : <ChevronDown size={14} />
                    )}
                  </div>
                </th>
                <th className="px-6 py-4 text-[10px] uppercase tracking-widest font-bold text-slate-400 dark:text-slate-500 text-right">A├º├Áes</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-50 dark:divide-slate-800">
              {paginatedProcedures.map((proc) => (
                <tr key={proc.id} className="hover:bg-slate-50/80 dark:hover:bg-slate-800/50 transition-colors group">
                  <td className="px-6 py-4">
                    <div className="flex flex-col">
                      <span className="font-bold text-slate-700 dark:text-slate-200 text-sm">{proc.name}</span>
                    </div>
                  </td>
                  <td className="px-6 py-4">
                    <span className={cn(
                      "px-3 py-1.5 rounded-xl text-[10px] font-bold uppercase tracking-wider border transition-all",
                      proc.modality === 'CONSULTA' ? "bg-emerald-50 dark:bg-emerald-900/30 text-emerald-600 dark:text-emerald-400 border-emerald-100 dark:border-emerald-800 shadow-sm shadow-emerald-50 dark:shadow-none" :
                      proc.modality === 'US' ? "bg-indigo-50 dark:bg-indigo-900/30 text-indigo-600 dark:text-indigo-400 border-indigo-100 dark:border-indigo-800 shadow-sm shadow-indigo-50 dark:shadow-none" :
                      proc.modality === 'CT' ? "bg-amber-50 dark:bg-amber-900/30 text-amber-600 dark:text-amber-400 border-amber-100 dark:border-amber-800 shadow-sm shadow-amber-50 dark:shadow-none" :
                      proc.modality === 'CR' ? "bg-sky-50 dark:bg-sky-900/30 text-sky-600 dark:text-sky-400 border-sky-100 dark:border-sky-800 shadow-sm shadow-sky-50 dark:shadow-none" :
                      "bg-slate-50 dark:bg-slate-800 text-slate-600 dark:text-slate-400 border-slate-100 dark:border-slate-700"
                    )}>
                      {proc.modality}
                    </span>
                  </td>
                  <td className="px-6 py-4">
                    <span className="text-sm font-bold text-slate-700 dark:text-slate-200">
                      R$ {parseFloat(proc.price).toLocaleString('pt-BR', { minimumFractionDigits: 2 })}
                    </span>
                  </td>
                  <td className="px-6 py-4 text-right">
                    <div className="flex items-center justify-end gap-1 opacity-0 group-hover:opacity-100 transition-all">
                      <button 
                        onClick={() => {
                          setEditingProcedure(proc);
                          setModalOpen(true);
                        }}
                        className="p-2 hover:bg-white dark:hover:bg-slate-800 rounded-lg text-slate-400 dark:text-slate-600 hover:text-indigo-600 dark:hover:text-indigo-400 transition-all border border-transparent hover:border-slate-100 dark:hover:border-slate-700"
                      >
                        <Edit2 size={14} />
                      </button>
                      <button 
                        onClick={() => setItemToDelete({ id: proc.id, name: proc.name, type: 'procedimento' })}
                        className="p-2 hover:bg-white dark:hover:bg-slate-800 rounded-lg text-slate-400 dark:text-slate-600 hover:text-red-500 dark:hover:text-red-400 transition-all border border-transparent hover:border-slate-100 dark:hover:border-slate-700"
                      >
                        <Trash2 size={14} />
                      </button>
                    </div>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
          {filteredProcedures.length === 0 && (
            <div className="p-12 text-center text-slate-400 italic text-sm">
              Nenhum procedimento encontrado para "{searchQuery}"
            </div>
          )}

          {/* Pagination Controls */}
          {totalPages > 1 && (
            <div className="flex flex-col sm:flex-row items-center justify-between gap-4 p-6 border-t border-slate-50 dark:border-slate-800 bg-slate-50/10 dark:bg-slate-900/10">
              <p className="text-[10px] text-slate-400 dark:text-slate-500 font-bold uppercase tracking-widest">
                Mostrando <span className="text-slate-600 dark:text-slate-300">{paginatedProcedures.length}</span> de <span className="text-slate-600 dark:text-slate-300">{filteredProcedures.length}</span> procedimentos
              </p>
              
              <div className="flex items-center gap-2">
                <button 
                  disabled={currentPage === 1}
                  onClick={() => setCurrentPage(prev => Math.max(1, prev - 1))}
                  className="w-10 h-10 rounded-xl border border-slate-200 flex items-center justify-center text-slate-400 hover:bg-white hover:text-indigo-600 disabled:opacity-30 disabled:hover:bg-transparent transition-all shadow-sm"
                >
                  <ChevronLeft size={18} />
                </button>
                
                <div className="flex items-center gap-1">
                  {Array.from({ length: totalPages }, (_, i) => i + 1)
                    .filter(page => {
                      return page === 1 || page === totalPages || Math.abs(page - currentPage) <= 1;
                    })
                    .map((page, index, array) => (
                      <React.Fragment key={page}>
                        {index > 0 && array[index - 1] !== page - 1 && (
                          <span className="text-slate-300 px-1 font-bold">...</span>
                        )}
                        <button 
                          onClick={() => setCurrentPage(page)}
                          className={cn(
                            "w-10 h-10 rounded-xl text-xs font-bold transition-all",
                            currentPage === page 
                              ? "bg-indigo-600 text-white shadow-lg shadow-indigo-100" 
                              : "text-slate-400 hover:bg-white hover:text-slate-600 border border-slate-100 hover:border-slate-200"
                          )}
                        >
                          {page}
                        </button>
                      </React.Fragment>
                    ))}
                </div>

                <button 
                  disabled={currentPage === totalPages}
                  onClick={() => setCurrentPage(prev => Math.min(totalPages, prev + 1))}
                  className="w-10 h-10 rounded-xl border border-slate-200 flex items-center justify-center text-slate-400 hover:bg-white hover:text-indigo-600 disabled:opacity-30 disabled:hover:bg-transparent transition-all shadow-sm"
                >
                  <ChevronRight size={18} />
                </button>
              </div>
            </div>
          )}
        </div>
      </div>

      {modalOpen && (
        <ProcedureModal 
          procedure={editingProcedure}
          onClose={() => setModalOpen(false)}
          onSave={handleSave}
        />
      )}

      {showImportModal && (
        <ImportProceduresModal 
          onClose={() => setShowImportModal(false)}
          onImport={onImport}
          existingProcedures={procedures}
        />
      )}

      {itemToDelete && (
        <DeleteConfirmationModal 
          itemName={itemToDelete.name}
          itemType={itemToDelete.type}
          onClose={() => setItemToDelete(null)}
          onConfirm={confirmDelete}
        />
      )}
    </div>
  );
}

function InsuranceModal({ insurance, onClose, onSave }: { insurance: any, onClose: () => void, onSave: (data: any) => void }) {
  const [name, setName] = useState(insurance?.name || '');
  const [status, setStatus] = useState(insurance?.status || 'Ativo');

  return (
    <div className="fixed inset-0 z-[100] flex items-center justify-center bg-slate-900/60 backdrop-blur-md p-4 animate-in fade-in duration-200">
      <div className="bg-white dark:bg-slate-900 rounded-[2.5rem] shadow-2xl w-full max-w-md overflow-hidden flex flex-col border border-white dark:border-slate-800 animate-in zoom-in-95 duration-300">
        <div className="p-8 border-b border-slate-50 dark:border-slate-800 flex justify-between items-center bg-slate-50/30 dark:bg-slate-900/50">
          <h2 className="text-xl font-bold text-slate-900 dark:text-white">{insurance ? 'Editar Conv├¬nio' : 'Novo Conv├¬nio'}</h2>
          <button onClick={onClose} className="p-2 text-slate-400 hover:text-slate-600 dark:hover:text-slate-300 hover:bg-white dark:hover:bg-slate-800 rounded-full transition-all border border-transparent hover:border-slate-100 dark:hover:border-slate-700">
            <X size={20} />
          </button>
        </div>
        <form onSubmit={(e) => { e.preventDefault(); onSave({ name, status }); }} className="p-8 space-y-6">
          <div className="space-y-2">
            <label className="text-[10px] font-bold text-slate-400 dark:text-slate-500 uppercase tracking-widest ml-1">Nome do Conv├¬nio</label>
            <input 
              type="text" 
              required
              className="w-full px-4 py-3 bg-slate-50 dark:bg-slate-800 border border-slate-200 dark:border-slate-700 rounded-2xl text-sm focus:ring-2 focus:ring-indigo-500 outline-none dark:text-white"
              value={name}
              onChange={(e) => setName(e.target.value)}
              placeholder="Ex: Unimed"
            />
          </div>
          <div className="space-y-2">
            <label className="text-[10px] font-bold text-slate-400 dark:text-slate-500 uppercase tracking-widest ml-1">Status</label>
            <select 
              className="w-full px-4 py-3 bg-slate-50 dark:bg-slate-800 border border-slate-200 dark:border-slate-700 rounded-2xl text-sm focus:ring-2 focus:ring-indigo-500 outline-none appearance-none dark:text-white"
              value={status}
              onChange={(e) => setStatus(e.target.value)}
            >
              <option value="Ativo">Ativo</option>
              <option value="Inativo">Inativo</option>
            </select>
          </div>
          <div className="flex gap-3 pt-4">
            <button type="button" onClick={onClose} className="flex-1 py-4 bg-slate-100 dark:bg-slate-800 text-slate-600 dark:text-slate-400 rounded-2xl font-bold text-sm">Cancelar</button>
            <button type="submit" className="flex-3 py-4 bg-indigo-600 text-white rounded-2xl font-bold text-sm shadow-xl shadow-indigo-100 dark:shadow-none flex items-center justify-center gap-2 px-8">
              <Save size={18} /> Salvar
            </button>
          </div>
        </form>
      </div>
    </div>
  );
}

function ProcedureModal({ procedure, onClose, onSave }: { procedure: any, onClose: () => void, onSave: (data: any) => void }) {
  const [name, setName] = useState(procedure?.name || '');
  const [modality, setModality] = useState(procedure?.modality || 'US');
  const [customModality, setCustomModality] = useState('');
  const [showCustomInput, setShowCustomInput] = useState(false);
  const [price, setPrice] = useState(procedure?.price || '');
  const [preparation, setPreparation] = useState(procedure?.preparation || '');
  const [integraRis, setIntegraRis] = useState(procedure?.integraRis || false);

  const standardModalities = [
    { code: 'US', label: 'Ultrassom', color: 'indigo' },
    { code: 'CR', label: 'Raio-X', color: 'sky' },
    { code: 'CT', label: 'Tomografia', color: 'amber' },
    { code: 'MG', label: 'Mamografia', color: 'rose' },
    { code: 'MR', label: 'Resson├óncia', color: 'violet' },
    { code: 'CONSULTA', label: 'Consulta', color: 'emerald' },
  ];

  // If initial modality is not in standard, it's custom
  React.useEffect(() => {
    if (procedure?.modality) {
      const isStandard = standardModalities.some(m => m.code === procedure.modality);
      if (!isStandard) {
        setModality('OUTRO');
        setCustomModality(procedure.modality);
        setShowCustomInput(true);
      }
    }
  }, [procedure]);

  const handleSave = (e: React.FormEvent) => {
    e.preventDefault();
    const finalModality = modality === 'OUTRO' ? customModality.toUpperCase() : modality;
    onSave({ 
      name: sanitize(name), 
      modality: finalModality, 
      price,
      preparation: preparation,
      integraRis: integraRis
    });
  };

  const sanitize = (str: string) => str.normalize("NFD").replace(/[\u0300-\u036f]/g, "");

  const formatCurrencyValue = (value: string) => {
    const numbers = value.replace(/\D/g, '');
    const amount = (parseFloat(numbers) / 100).toFixed(2);
    if (isNaN(parseFloat(amount))) return '';
    return amount.replace('.', ',');
  };

  const handlePriceChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const value = e.target.value.replace(/\D/g, '');
    if (!value) {
      setPrice('');
      return;
    }
    const amount = (parseFloat(value) / 100).toFixed(2);
    setPrice(amount);
  };

  return (
    <div className="fixed inset-0 z-[100] flex items-center justify-center bg-slate-900/60 backdrop-blur-md p-4 animate-in fade-in duration-200">
      <div className="bg-white dark:bg-slate-900 rounded-[3rem] shadow-2xl w-full max-w-4xl overflow-hidden flex flex-col border border-white dark:border-slate-800 animate-in zoom-in-95 duration-300 max-h-[90vh]">
        <div className="p-10 border-b border-slate-50 dark:border-slate-800 flex justify-between items-center bg-slate-50/30 dark:bg-slate-900/50">
          <div>
            <h2 className="text-2xl font-black text-slate-900 dark:text-white">{procedure ? 'Editar Procedimento' : 'Novo Procedimento'}</h2>
            <p className="text-xs text-slate-500 dark:text-slate-400 font-bold uppercase tracking-widest mt-1">Configure os detalhes e modalidade t├®cnica</p>
          </div>
          <button onClick={onClose} className="p-2 text-slate-400 hover:text-slate-600 dark:hover:text-slate-300 hover:bg-white dark:hover:bg-slate-800 rounded-full transition-all border border-transparent hover:border-slate-100 dark:hover:border-slate-700">
            <X size={20} />
          </button>
        </div>
        <form onSubmit={handleSave} className="p-10 space-y-10 overflow-y-auto no-scrollbar">
          <div className="grid grid-cols-1 lg:grid-cols-5 gap-12">
            <div className="lg:col-span-2 space-y-8">
              <div className="space-y-2">
                <label className="text-[10px] font-bold text-slate-400 dark:text-slate-500 uppercase tracking-widest ml-1">Descri├º├úo do Procedimento</label>
                <input 
                  type="text" 
                  required
                  className="w-full px-6 py-4 bg-slate-50 dark:bg-slate-800 border border-slate-200 dark:border-slate-700 rounded-2xl text-sm font-medium focus:ring-4 focus:ring-indigo-500/10 focus:border-indigo-500/50 focus:bg-white dark:focus:bg-slate-700 outline-none transition-all placeholder:text-slate-300 dark:text-slate-100"
                  value={name}
                  onChange={(e) => setName(e.target.value)}
                  placeholder="Ex: Ultrassom de Abdome Total"
                />
              </div>

              <div className="space-y-2">
                <label className="text-[10px] font-bold text-slate-400 dark:text-slate-500 uppercase tracking-widest ml-1">Valor Sugerido (R$)</label>
                <div className="relative group">
                  <div className="absolute left-6 top-1/2 -translate-y-1/2 flex items-center gap-2 pointer-events-none">
                    <span className="text-slate-400 dark:text-slate-500 font-black text-base group-focus-within:text-indigo-600 transition-colors">R$</span>
                    <div className="w-px h-5 bg-slate-200 dark:bg-slate-700 group-focus-within:bg-indigo-300 transition-colors" />
                  </div>
                  <input 
                    type="text" 
                    required
                    className="w-full pl-24 pr-6 py-5 bg-slate-50 dark:bg-slate-800 border border-slate-200 dark:border-slate-700 rounded-2xl text-base font-black focus:ring-4 focus:ring-indigo-500/10 focus:border-indigo-500/50 focus:bg-white dark:focus:bg-slate-700 outline-none transition-all dark:text-white"
                    value={price ? parseFloat(price).toLocaleString('pt-BR', { minimumFractionDigits: 2 }) : ''}
                    onChange={handlePriceChange}
                    placeholder="0,00"
                  />
                </div>
              </div>

              <div className="space-y-2">
                <label className="text-[10px] font-bold text-slate-400 dark:text-slate-500 uppercase tracking-widest ml-1">Modelo de Preparo</label>
                <textarea 
                  rows={4}
                  className="w-full px-6 py-4 bg-slate-50 dark:bg-slate-800 border border-slate-200 dark:border-slate-700 rounded-2xl text-sm font-medium focus:ring-4 focus:ring-indigo-500/10 focus:border-indigo-500/50 focus:bg-white dark:focus:bg-slate-700 outline-none transition-all placeholder:text-slate-300 dark:text-slate-100 resize-none"
                  value={preparation}
                  onChange={(e) => setPreparation(e.target.value)}
                  placeholder="Instru├º├Áes de preparo para o paciente..."
                />
              </div>

              <div className="space-y-4 pt-4 border-t border-slate-50 dark:border-slate-800">
                <label className="flex items-center justify-between p-4 bg-white dark:bg-slate-800 border border-slate-100 dark:border-slate-700 rounded-2xl cursor-pointer hover:bg-slate-50 dark:hover:bg-slate-700 transition-colors shadow-sm">
                  <div className="flex items-center gap-3">
                    <div className={cn("w-8 h-8 rounded-lg flex items-center justify-center", integraRis ? "bg-indigo-50 dark:bg-indigo-900/30 text-indigo-600 dark:text-indigo-400" : "bg-slate-50 dark:bg-slate-900 text-slate-300 dark:text-slate-600")}>
                      <Activity size={18} />
                    </div>
                    <div>
                      <span className="text-xs font-bold text-slate-700 dark:text-slate-200">Integra RIS</span>
                      <p className="text-[9px] text-slate-400 dark:text-slate-500 font-medium">Habilitar exporta├º├úo autom├ítica para o RIS/PACS.</p>
                    </div>
                  </div>
                  <div 
                    onClick={() => setIntegraRis(!integraRis)}
                    className={cn(
                      "w-12 h-6 rounded-full transition-colors relative",
                      integraRis ? "bg-indigo-600" : "bg-slate-200"
                    )}
                  >
                    <div className={cn(
                      "absolute top-1 w-4 h-4 bg-white rounded-full transition-all shadow-sm",
                      integraRis ? "left-7" : "left-1"
                    )} />
                  </div>
                </label>
              </div>
            </div>

            <div className="lg:col-span-3 space-y-6">
              <div className="space-y-3">
                <label className="text-[10px] font-bold text-slate-400 dark:text-slate-500 uppercase tracking-widest ml-1">Modalidade T├®cnica</label>
                <div className="grid grid-cols-2 sm:grid-cols-3 gap-4">
                  {standardModalities.map((m) => {
                    const colorMap: Record<string, string> = {
                      indigo: modality === m.code ? "bg-indigo-50 border-indigo-500 shadow-indigo-100 text-indigo-600" : "text-slate-400 border-slate-100",
                      sky: modality === m.code ? "bg-sky-50 border-sky-500 shadow-sky-100 text-sky-600" : "text-slate-400 border-slate-100",
                      amber: modality === m.code ? "bg-amber-50 border-amber-500 shadow-amber-100 text-amber-600" : "text-slate-400 border-slate-100",
                      rose: modality === m.code ? "bg-rose-50 border-rose-500 shadow-rose-100 text-rose-600" : "text-slate-400 border-slate-100",
                      violet: modality === m.code ? "bg-violet-50 border-violet-500 shadow-violet-100 text-violet-600" : "text-slate-400 border-slate-100",
                      emerald: modality === m.code ? "bg-emerald-50 border-emerald-500 shadow-emerald-100 text-emerald-600" : "text-slate-400 border-slate-100",
                    };
                    
                    const dotColorMap: Record<string, string> = {
                      indigo: "bg-indigo-500",
                      sky: "bg-sky-500",
                      amber: "bg-amber-500",
                      rose: "bg-rose-500",
                      violet: "bg-violet-500",
                      emerald: "bg-emerald-500",
                    };

                    return (
                      <button
                        key={m.code}
                        type="button"
                        onClick={() => {
                          setModality(m.code);
                          setShowCustomInput(false);
                        }}
                        className={cn(
                          "flex flex-col items-center justify-center p-4 rounded-2xl border-2 transition-all group relative overflow-hidden",
                          colorMap[m.color],
                          modality === m.code ? "shadow-lg" : "bg-white hover:border-slate-200 hover:bg-slate-50"
                        )}
                      >
                        <span className={cn(
                          "text-lg font-black mb-1 transition-transform group-active:scale-90",
                        )}>{m.code}</span>
                        <span className={cn(
                          "text-[9px] font-bold uppercase tracking-widest opacity-80 text-center",
                        )}>{m.label}</span>
                        
                        {modality === m.code && (
                          <div className={cn("absolute top-2 right-2 w-2 h-2 rounded-full animate-pulse", dotColorMap[m.color])} />
                        )}
                      </button>
                    );
                  })}
                  
                  {/* Option for New Modality */}
                  <button
                    type="button"
                    onClick={() => {
                      setModality('OUTRO');
                      setShowCustomInput(true);
                    }}
                    className={cn(
                      "flex flex-col items-center justify-center p-4 rounded-2xl border-2 transition-all group relative",
                      modality === 'OUTRO' 
                        ? "bg-slate-900 border-slate-900 text-white shadow-xl" 
                        : "bg-slate-50 border-slate-200 text-slate-400 hover:bg-slate-100"
                    )}
                  >
                    <Plus size={20} className="mb-1" />
                    <span className="text-[9px] font-bold uppercase tracking-widest">Nova Modl.</span>
                  </button>
                </div>

                {showCustomInput && (
                  <div className="mt-4 animate-in slide-in-from-top-2 duration-300">
                    <label className="text-[10px] font-bold text-slate-400 dark:text-slate-500 uppercase tracking-widest ml-1">Especificar Nova Modalidade</label>
                    <input 
                      type="text"
                      placeholder="DIX, PET, etc..."
                      className="w-full px-4 py-3 mt-2 bg-slate-50 dark:bg-slate-800 border border-slate-200 dark:border-slate-700 rounded-xl text-sm font-black focus:ring-2 focus:ring-slate-900 dark:focus:ring-indigo-500 focus:bg-white dark:focus:bg-slate-700 outline-none transition-all uppercase dark:text-white"
                      value={customModality}
                      onChange={(e) => setCustomModality(e.target.value)}
                      required={modality === 'OUTRO'}
                    />
                  </div>
                )}
              </div>
            </div>
          </div>
          <div className="flex gap-3 pt-4">
            <button type="button" onClick={onClose} className="flex-1 py-4 bg-slate-100 dark:bg-slate-800 text-slate-600 dark:text-slate-400 rounded-2xl font-bold text-sm">Cancelar</button>
            <button type="submit" className="flex-3 py-4 bg-indigo-600 text-white rounded-2xl font-bold text-sm shadow-xl shadow-indigo-100 dark:shadow-none flex items-center justify-center gap-2 px-8">
              <Save size={18} /> Salvar
            </button>
          </div>
        </form>
      </div>
    </div>
  );
}

